  ('disabled-57f41407-moex-00132', 'disabled-57f41407', 'disabled-57f41407-moex-114-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲夫乙妻育有子女丙、丁、戊，甲、乙均已過世。丙無配偶及子嗣，於遺 囑中將其遺產全數留予弟弟丁。不料丙過世前一日，丁暴疾身亡，丁留下 配偶A及一女B。丙之遺產應由何人繼承？', '["丁", "戊", "A", "B"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "d2124292ad0a", "answer_pdf_sha1": "f10b97dd76ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0309", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
