  ('disabled-57f41407-moex-00135', 'disabled-57f41407', 'disabled-57f41407-moex-114-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲受死亡宣告後，關於甲之法律關係之敘述，下列何者正確？', '["甲若事實上仍生存，則其在原住所以外之地所為之法律行為仍有效", "甲受死亡宣告後又回至原住所地時，則甲所為之一切行為不生效力", "甲如係因特別災難而受死亡宣告時，該特別災難結束時，視為甲死亡之 時點", "甲如係因一般事由而受死亡宣告時，死亡宣告裁判內所確定死亡之時， 擬制為其死亡之時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "d2124292ad0a", "answer_pdf_sha1": "f10b97dd76ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0309", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
